from flask import Flask, request, jsonify
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.DEBUG,
                    format='%(asctime)s - %(levelname)s - %(message)s')

@app.before_request
def log_request_info():
    app.logger.debug('Headers: %s', request.headers)
    app.logger.debug('Body: %s', request.get_data(as_text=True))
    if 'Authorization' in request.headers:
        app.logger.debug('Authorization Token: %s', request.headers['Authorization'])
    return None

@app.after_request
def log_response_info(response):
    app.logger.debug('Response Status: %s', response.status)
    return response

@app.errorhandler(Exception)
def handle_exception(e):
    app.logger.error('An error occurred: %s', str(e))
    return jsonify(error=str(e)), 500

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')
    if username == 'admin' and password == 'secret':
        app.logger.info('Login successful for user: %s', username)
        return jsonify(message='Login successful'), 200
    else:
        app.logger.error('Failed login attempt for user: %s', username)
        return jsonify(error='Invalid credentials'), 401

if __name__ == '__main__':
    app.run(debug=True)